  (184, 'Cornwall Council automated credit (rates refund/grant)', 'AUTOMATED CREDIT.*CORNWALL COUNCIL', NULL, '>', 0, ARRAY[1]::int[], 'income_other', 0.85, 'panel 2026-07-10, verified CONFIRMED; Same anchor mismatch as the DD variant but opposite direction. Account 15 only, 11 credits 2020-2025 ranging £132-£9000, consistent with business rates relief/grant refunds paid to the pub by the council (2020-21 rows align with COVID rates-relief grant period).'),
  (185, 'GoCardless aggregator DD (prefix variant)', 'DIRECT DEBIT.*GOCARDLESS', NULL, '<', 0, ARRAY[1]::int[], 'direct_debit', 0.90, 'panel 2026-07-10, verified CONFIRMED; Existing rule 45 ''DD aggregator — GoCardless'' is anchored ^GOCARDLESS and misses rows prefixed ''Direct Debit '' / ''DIRECT DEBIT ,''. Account 15 only, 86 rows, all negative, various sub-merchants under the GoCardless rail (CLEARBREW, TAMARKOFFI, CELTICBOOKKE) — same generic direct_debit treatment as the existing rule applies to any GoCardless payee.'),
  (186, 'Caterbook Ltd DD (booking/EPOS subscription)', 'CATERBOOK LTD', NULL, '<', 0, ARRAY[1]::int[], 'direct_debit', 0.90, 'panel 2026-07-10, verified CONFIRMED; No existing rule. Account 15 only, 56 rows, consistent recurring negative £12-£319 direct debit to Caterbook Ltd, ref 3S2GGZY throughout — Caterbook is the pub''s known booking/EPOS platform (per memory).'),
